document.addEventListener('click',(e)=>{
    const menu=document.querySelector('.menu');
    const sidebar=document.querySelector('.sidenav');

    if(e.target.closest('.menu')){
    sidebar.classList.toggle('active-sidenav');
    e.stopPropagation();
    menu.setAttribute('src', sidebar.classList.contains('active-sidenav') ? 'assets/menu-opened.svg' : 'assets/menu-closed.svg');
    }

    else if(!sidebar.contains(e.target) && sidebar.classList.contains('active-sidenav')){
        sidebar.classList.remove('active-sidenav');
        menu.setAttribute('src','assets/menu-closed.svg');
    }
    if(e.target.closest('#backtotop')){
        document.body.scrollTop = 0;
        document.documentElement.scrollTop = 0; 
    }
});

