let backtotop = document.getElementById('backtotop');
window.onscroll = function(){
    if(backtotop){
        if(document.body.scrollTop>500 || document.documentElement.scrollTop>500){
            backtotop.style.display= "block";
        }
        else{
            backtotop.style.display= "none";
        }
    }
}


const contactForm = document.getElementById('contactForm')
if(contactForm){
contactForm.addEventListener('submit', function(e) {
  e.preventDefault();

  const name = document.getElementById('name').value;
  const email = document.getElementById('email').value;
  const message = document.getElementById('message').value;

  const subject = encodeURIComponent("New Inquiry from " + name);
  const body = encodeURIComponent(`Name: ${name}\nEmail: ${email}\n\nMessage:\n${message}`);

  
  window.open(`mailto:rishigardenshotel@gmail.com?subject=${subject}&body=${body}`);

  document.getElementById('contactForm').classList.add('hidden');
  const loading =document.getElementById('contactMessage')
  loading.classList.remove('hidden');
  setTimeout(() => {
    loading.classList.add('hidden');
    document.getElementById('successMessage').classList.remove('hidden');
   }
    , 5000);
    setTimeout(() => {
   document.querySelector('.sucimg').classList.remove('hidden');
   document.querySelector('.sucgif').classList.add('hidden');
   }, 10000);
});
}

