/* Blog section rendering */

const blogContents = document.getElementById('blog-contents');


function renderimage(){
  if(!blogContents){
   return;
 }
    const blogPost = posts.map(post => `
        <div class="blog-card" data-post-slug="${post.slug}" data-post-title="${post.title}" data-post-description="${post.description}" data-post-date="${post.postDate}" data-category="${post.category}">
                <h2 class="blog-card-title">${post.title}</h2>
                <div class="blog-card-img">
                    <img src="${post.image}" alt="garden image">
                    <div class="blog-card-share">
                    <button class="share-btn">
                        <img src="assets/share.svg" alt="share icon">
                    </button>
                    </div>
                </div>
                <div class="blog-card-description-container">
                    <p class="blog-card-description">${post.description}</p>
                </div>
                <p class="blog-card-posted-date"><strong>Posted on: </strong><span class="post-date">${post.postDate}</span></p>
        </div>
    `).join(' ');
    blogContents.innerHTML = blogPost;
    setupShareButtons();
}

       /* The Below parts are made with AI */

/* Share button functionality - disclaimer: used ai for this.*/
function setupShareButtons() {
  const shareButtons = document.querySelectorAll('.share-btn');
  const baseUrl = window.location.origin;

  shareButtons.forEach(btn => {
    btn.replaceWith(btn.cloneNode(true));
  });
  
  document.querySelectorAll('.share-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const card = btn.closest('.blog-card');
      const toast = card.querySelector('.share-toast');
      
      const title = card.dataset.postTitle;
      const description = card.dataset.postDescription;
      const postDate = card.dataset.postDate;
      const url = `${baseUrl}`; // shares main page for now
      
      const shareText = `*${title}*\n\n${description}\n\nPosted on: ${postDate}\n\n${url}`;
      
      if (navigator.share) {
        try {
          await navigator.share({ title, text: shareText, url });
        } catch (err) {}
      } else {
        try {
          await navigator.clipboard.writeText(shareText);
          toast.classList.remove('hidden');
          setTimeout(() => toast.classList.add('hidden'), 2000);
        } catch (err) {}
      }
    });
  });
}

function setupCategoryFilter() {
  const filterButtons = document.querySelectorAll('.filter-btn');
  
  filterButtons.forEach(btn => {
    btn.addEventListener('click', () => {
      const category = btn.id.replace('filter-', ''); // gets "infrastructure" from id
      const allCards = document.querySelectorAll('.blog-card');
      
      allCards.forEach(card => {
        if (category === 'all'){
          card.style.display = 'block';
          document.documentElement.scrollTop=0;
          document.body.scrollTop = 0;
        }
          else if(card.dataset.category === category) {
          card.style.display = 'block'; // Show it
        } else {
          card.style.display = 'none'; // Hide it
        }
      });
  });
});
}

function renderRecentPosts() {
  const recentContainer = document.getElementById('recent-posts-row');
  if (!recentContainer) return;
  
  // Step 1: Sort posts by date, newest first
  const sortedPosts = posts.sort((a, b) => {
    // Convert "28-04-2026" to Date object
    const dateA = new Date(a.postDate.split('-').reverse().join('-')); // DD-MM-YYYY to YYYY-MM-DD
    const dateB = new Date(b.postDate.split('-').reverse().join('-'));
    return dateB - dateA; // Newest first
  });
  
  // Step 2: Take first 5
  const recent5 = sortedPosts.slice(0, 5);
  
  // Step 3: Render small cards
  const recentHTML = recent5.map(post => `
    <div class="recent-card" data-post-slug="${post.slug}">
      <img src="${post.image}" alt="${post.title}">
      <p class="recent-card-title">${post.title}</p>
      <p class="recent-card-date">${post.postDate}</p>
    </div>
  `).join('');
  
  recentContainer.innerHTML = recentHTML;
  
  // Step 4: Make small cards clickable - scroll to main card
  document.querySelectorAll('.recent-card').forEach(card => {
    card.addEventListener('click', () => {
      const slug = card.dataset.postSlug;
      const mainCard = document.querySelector(`.blog-card[data-post-slug="${slug}"]`);
      if (mainCard) {
        mainCard.scrollIntoView({ behavior: 'smooth', block: 'center' });
        mainCard.style.background = '#ff6200';
        setTimeout(() => mainCard.style.background = 'white', 2000);
      }
    });
  });
}

function hideOldPost(){
  const allCards = document.querySelectorAll('.blog-card');
  const today = new Date().getTime();
  allCards.forEach(card =>{
    const uploadDate = new Date((card.dataset.postDate).split('-').reverse().join('-')).getTime();
    if((today - uploadDate) >= (30 * 1000 * 60 * 60 *24) ){
      card.style.display = 'none';
    }
  });
}

document.addEventListener('DOMContentLoaded',() => {
  renderimage();
  setupCategoryFilter();
  renderRecentPosts();
  hideOldPost();
});
